  1	import * as React from "react";
  2	import * as _ from "lodash-es";
  3	import { PencilAltIcon } from "@patternfly/react-icons";
  4	import {
  5	  Breadcrumb,
  6	  BreadcrumbItem,
  7	  Button,
  8	  Flex,
  9	  FlexItem,
 10	  DescriptionListGroup,
 11	  DescriptionListTerm,
 12	  DescriptionListDescription,
 13	} from "@patternfly/react-core";
 14	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 15	import { K8sResourceKind } from "../k8s/types";
 16	import * as classnames from "classnames";
 17	import "./details-item.css";
 18	
 19	import { toPath, isEmpty, get } from "lodash-es";
 20	
 21	export const PropertyPath = ({ kind, path }) => {
 22	  const pathArray: string[] = toPath(path);
 23	  return (
 24	    <Breadcrumb>
 25	      <BreadcrumbItem>{kind}</BreadcrumbItem>
 26	      {pathArray.map((property, i) => {
 27	        const isLast = i === pathArray.length - 1;
 28	        return (
 29	          <BreadcrumbItem key={i} isActive={isLast}>
 30	            {property}
 31	          </BreadcrumbItem>
 32	        );
 33	      })}
 34	    </Breadcrumb>
 35	  );
 36	};
 37	
 38	const EditButton: React.FC<EditButtonProps> = (props) => {
 39	  return (
 40	    <Button
 41	      type="button"
 42	      variant="link"
 43	      isInline
 44	      onClick={props.onClick}
 45	      data-test={
 46	        props.testId
 47	          ? `${props.testId}-details-item__edit-button`
 48	          : "details-item__edit-button"
 49	      }
 50	    >
 51	      {props.children} <PencilAltIcon />
 52	    </Button>
 53	  );
 54	};
 55	
 56	export const DetailsItem: React.FC<DetailsItemProps> = ({
 57	  children,
 58	  defaultValue = "-",
 59	  editAsGroup,
 60	  hideEmpty,
 61	  label,
 62	  obj,
 63	  onEdit,
 64	  canEdit = true,
 65	  path,
 66	  valueClassName,
 67	}) => {
 68	  const { t } = useNodeHealthCheckTranslation();
 69	  const hide = hideEmpty && isEmpty(get(obj, path));
 70	  const value: React.ReactNode = children ?? get(obj, path, defaultValue);
 71	  const editable = onEdit && canEdit;
 72	  return hide ? null : (
 73	    <DescriptionListGroup>
 74	      <DescriptionListTerm
 75	        className="nhc-details-term"
 76	        data-test-selector={`details-item-label__${label}`}
 77	      >
 78	        <Flex
 79	          fullWidth={{ default: "fullWidth" }}
 80	          justifyContent={{ default: "justifyContentSpaceBetween" }}
 81	          alignItems={{ default: "alignItemsCenter" }}
 82	        >
 83	          <FlexItem>{label}</FlexItem>
 84	          {editable && editAsGroup && (
 85	            <FlexItem>
 86	              <EditButton testId={label} onClick={onEdit}>
 87	                {t("Edit")}
 88	              </EditButton>
 89	            </FlexItem>
 90	          )}
 91	        </Flex>
 92	      </DescriptionListTerm>
 93	      <DescriptionListDescription
 94	        className={classnames(valueClassName)}
 95	        data-test-selector={`details-item-value__${label}`}
 96	      >
 97	        {editable && !editAsGroup ? (
 98	          <EditButton testId={label} onClick={onEdit}>
 99	            {value}
100	          </EditButton>
101	        ) : (
102	          value
103	        )}
104	      </DescriptionListDescription>
105	    </DescriptionListGroup>
106	  );
107	};
108	
109	export type DetailsItemProps = {
110	  canEdit?: boolean;
111	  defaultValue?: React.ReactNode;
112	  editAsGroup?: boolean;
113	  hideEmpty?: boolean;
114	  label: string;
115	  labelClassName?: string;
116	  obj: K8sResourceKind;
117	  onEdit?: (e: React.MouseEvent<HTMLButtonElement>) => void;
118	  path?: string | string[];
119	  valueClassName?: string;
120	};
121	
122	type EditButtonProps = {
123	  onClick: (e: React.MouseEvent<HTMLButtonElement>) => void;
124	  testId?: string;
125	};
126	
127	DetailsItem.displayName = "DetailsItem";
128	PropertyPath.displayName = "PropertyPath";
129	EditButton.displayName = "EditButton";

